from dataclasses import dataclass

@dataclass
class Usage:
    prompt_tokens: int
    completion_tokens: int
    total_cost: float

PRICING = {'gpt-4': {'input': 0.03, 'output': 0.06}}

def calc_cost(model: str, usage: dict) -> float:
    p = PRICING[model]
    return usage['prompt_tokens'] * p['input'] / 1000 + usage['completion_tokens'] * p['output'] / 1000

import numpy as np

def cosine_similarity(a: list[float], b: list[float]) -> float:
    a, b = np.array(a), np.array(b)
    return float(np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b)))

def top_k(query_emb: list[float], chunks: list, k: int = 3):
    scores = [(c, cosine_similarity(query_emb, c.embedding)) for c in chunks]
    return sorted(scores, key=lambda x: x[1], reverse=True)[:k]

def retrieval_precision(retrieved: list[str], relevant: set[str]) -> float:
    if not retrieved:
        return 0.0
    hits = sum(1 for r in retrieved if r in relevant)
    return hits / len(retrieved)

def retrieval_recall(retrieved: list[str], relevant: set[str]) -> float:
    if not relevant:
        return 0.0
    hits = sum(1 for r in retrieved if r in relevant)
    return hits / len(relevant)

tools = {
    'search': lambda q: f'Search results for: {q}',
    'calculate': lambda expr: str(eval(expr)),
}

def call_tool(name: str, *args):
    if name not in tools:
        raise ValueError(f'Unknown tool: {name}')
    return tools[name](*args)

def plan(user_input: str, tools: list[str]) -> list[str]:
    steps = []
    if 'search' in user_input.lower():
        steps.append('search')
    if any(c.isdigit() for c in user_input):
        steps.append('calculate')
    return steps or ['search']

def execute_plan(steps: list[str], tools: dict, query: str) -> str:
    result = query
    for step in steps:
        try:
            result = tools[step](result)
        except Exception as e:
            return f'Error in {step}: {e}'
    return result

BLOCKED_PATTERNS = ['rm -rf', 'DROP TABLE', 'DELETE FROM']

def check_safety(action: str) -> bool:
    for pattern in BLOCKED_PATTERNS:
        if pattern in action:
            raise PermissionError(f'Blocked dangerous action: {pattern}')
    return True

from collections import deque

class ConversationMemory:
    def __init__(self, max_turns: int = 10):
        self.history: deque = deque(maxlen=max_turns)

    def add(self, role: str, content: str):
        self.history.append({'role': role, 'content': content})

    def get_context(self) -> list[dict]:
        return list(self.history)
